30	export function processScenario(input: any): unknown {
31	  const results: Array<{ premium: number } | { payout: number; remainingCap: number }> = [];
32	  const policies: Policy[] = [];
33	  let quoteCount = 0;
34	  for (const step of input.steps) {
35	    if (step.op === "claim") {
36	      const policy = policies[step.policy];
37	      let payout = 0;
38	      for (const damage of step.incident.damages) {
39	        const item = policy.items.find((it) => it.type === damage.itemType);
40	        let reimbursement: number;
